SELECT COUNT(*) AS total_tiles
FROM dataset_tiles
WHERE dataset_id = 1;

SELECT dataset_id, COUNT(tile_id) AS total_tiles
FROM dataset_tiles
GROUP BY dataset_id;

SELECT dataset_name
FROM geospatial_datasets
ORDER BY dataset_name;

SELECT dataset_id, MAX(last_updated) AS latest_update
FROM geospatial_datasets
GROUP BY dataset_id;

SELECT dataset_name, last_updated
FROM geospatial_datasets
ORDER BY last_updated DESC;

SELECT dataset_name
FROM geospatial_datasets
ORDER BY dataset_name ASC;
